INSERT INTO `MD_PROCESS` VALUES (1,1,4,2,'PRO-UDP','Unidad Desarrollo del Producto','Desarrollo técnico integral del producto (prenda textil)','Desarrollar prototipos técnicos, elaborar fichas técnicas, crear moldes escalados y coordinar con todas las áreas para garantizar la factibilidad de producción de una Orden de Pedido','2','1',45,'UDP - Unidad de Desarrollo de Producto','Nancy Marzal (Coordinación) / Dana Zavalaga (Analista) /Otros','No',1,'MAGREDA','2026-03-02 19:13:20.000','2026-03-12 08:18:47.529','UPDATE',1),(2,1,4,5,'PRO-PG','Coordinación integral producción','Coordinar y Ejecutar la atención de una Orden de Pedido de marcas propias y de marcas externas internacionales. Responsable del Flujo del Proceso: Corte → Bordado → Confección → Acabados','Coordinar y ejecutar la producción desde recepción de Orden de Pedido  (OP) hasta producto terminado, garantizando calidad, tiempos y proceso completo.','2','1',120,'Producción General','Ing. Guillermo Pachas/ Ricardo Higa','Intertek',1,'MAGREDA','2026-03-02 19:41:22.000','2026-03-16 00:38:45.042','UPDATE',1),(3,1,4,1,'PRO-COM','Gestión comercial y generación de órdenes de pedido','Contacta con cliente, recibe la OP, la pasa a formato KUSA y envía a áreas responsables para su atención.','Realizar estudio de mercado, generar diseños, coordinar con UDP para desarrollo técnico y gestionar el ciclo completo de ventas B2C para marcas propias, para marcas externas atención completa de la OP (Orden de Pedido).','2','1',45,'Comercial','Blanca Olortegui','Datos requeridos: Nombre, Entidad Certificadora, fecha de expedición y fecha de caducidad. Para todos los certificados.',1,'MAGREDA','2026-03-02 20:28:47.000','2026-03-16 01:54:44.561','UPDATE',1),(4,1,4,3,'PRO-TEX','Gestión y auditoría de materiales textiles','Gestión y auditoría de materiales textiles para la marca QAPARY','Verificar, auditar y liberar telas según especificaciones técnicas para marca QAPARY (Marca propia) y otras marcas.','2','1',11,'Textil','Ruth Chapuñan',NULL,1,'SYSTEM','2026-03-15 01:54:48.702','2026-03-17 20:56:17.801','UPDATE',1),(5,1,4,4,'PRO-LOG','Coordinación logística integral','Coordinación logística integral (Materiales y Avíos).','Gestionar la cadena de suministro completa desde almacenes hasta despacho final, garantizando disponibilidad de materiales y entrega oportuna.','2','2',7,'Logística - Almacén de Telas','Cristian Carpio',NULL,1,'SYSTEM','2026-03-16 00:42:42.055','2026-03-16 00:42:42.055','INSERT',1),(6,1,4,6,'PRO-QC','Control de calidad integral producción','Control de calidad integral del producto','Implementar control de calidad en todas las etapas productivas, desde materias primas\nhasta producto terminado, garantizando conformidad con especificaciones técnicas','2','2',0,'Calidad - Producción General','Paul Vargas',NULL,1,'SYSTEM','2026-03-16 00:48:07.461','2026-03-16 00:48:07.461','INSERT',1);
/*!40000 ALTER TABLE `MD_PROCESS` ENABLE KEYS */;
