INSERT INTO `MD_PRODUCTION_CHAIN` VALUES (1,'T4',1,5,1,'Cultivo del Algodón','Es un proceso agrícola clave para la industria textil, basado en la producción de fibra natural.',1,'MAGREDA','2026-02-27 19:11:45.000','2026-03-08 05:42:03.059','UPDATE',1),(2,'T3',1,4,2,'Hilado','El eslabón de hilado es el punto de inflexión en la cadena textil, donde las materias primas (fibras) dejan de ser un cúmulo amorfo para convertirse en un producto con estructura: el hilo. Es el proceso que conecta la obtención de fibras con la tejeduría.',1,'MAGREDA','2026-02-27 19:13:27.000','2026-03-08 05:42:33.602','UPDATE',1),(3,'T2',1,3,3,'Tejeduría de Tela ','El eslabón de la tejeduría (fabricación de tela) es el proceso donde el hilo se entrelaza para formar una superficie plana y flexible.\r\n',1,'MAGREDA','2026-02-27 19:14:58.000','2026-03-08 05:43:00.131','UPDATE',1),(4,'T1',1,2,4,'Confección','El eslabón de la confección es la etapa final de transformación física en la cadena textil. Aquí es donde la superficie bidimensional (la tela) se convierte en un producto tridimensional funcional (la prenda). ',1,'MAGREDA','2026-02-27 19:15:40.000','2026-03-14 08:37:34.386','UPDATE',1),(5,'T0',1,1,5,'Marca','El eslabón de la Marca (o Branding/Comercialización) es el eslabón final y estratégico de la cadena. Aquí, el producto físico (la prenda confeccionada) se transforma en un activo intangible con valor de mercado.',1,'MAGREDA','2026-02-27 19:16:20.000','2026-03-08 05:43:51.183','UPDATE',1);
/*!40000 ALTER TABLE `MD_PRODUCTION_CHAIN` ENABLE KEYS */;
UNLOCK TABLES;

